import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { BookingRecord } from "../types";

const API_BASES = ["http://localhost:5000/api", "http://127.0.0.1:5000/api"];

const Bookings: React.FC = () => {
  const [bookings, setBookings] = useState<BookingRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [query, setQuery] = useState("");
  const [activeId, setActiveId] = useState("");

  const fetchBookings = async () => {
    setLoading(true);
    setError("");

    for (const base of API_BASES) {
      try {
        const response = await axios.get<BookingRecord[]>(`${base}/bookings`);
        setBookings(response.data);
        setLoading(false);
        return;
      } catch (fetchError) {
        console.error(`Failed to fetch bookings from ${base}`, fetchError);
      }
    }

    setError("Could not load bookings. Start backend with: cd backend && node server.js");
    setLoading(false);
  };

  useEffect(() => {
    fetchBookings();
  }, []);

  const cancelBooking = async (bookingId: string) => {
    setActiveId(bookingId);
    setError("");

    for (const base of API_BASES) {
      try {
        const response = await axios.patch<{ booking: BookingRecord }>(`${base}/bookings/${bookingId}/cancel`);
        setBookings((current) =>
          current.map((booking) => (booking._id === bookingId ? response.data.booking : booking))
        );
        setActiveId("");
        return;
      } catch (requestError) {
        console.error(`Failed to cancel booking via ${base}`, requestError);
        if (axios.isAxiosError(requestError) && requestError.response?.data?.message) {
          setError(String(requestError.response.data.message));
          setActiveId("");
          return;
        }
      }
    }

    setError("Could not connect to backend. Start backend with: cd backend && node server.js");
    setActiveId("");
  };

  const filteredBookings = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return bookings;

    return bookings.filter((booking) => {
      return (
        booking.bookingCode.toLowerCase().includes(q) ||
        booking.busName.toLowerCase().includes(q) ||
        booking.route.toLowerCase().includes(q) ||
        booking.passengerDetails.some((p) => p.name.toLowerCase().includes(q))
      );
    });
  }, [bookings, query]);

  const totalRevenue = useMemo(() => {
    return bookings.filter((booking) => booking.status === "Confirmed").reduce((sum, booking) => sum + booking.totalPrice, 0);
  }, [bookings]);

  const todaysBookings = useMemo(() => {
    const today = new Date().toDateString();
    return bookings.filter((booking) => new Date(booking.bookedAt).toDateString() === today).length;
  }, [bookings]);

  return (
    <section className="space-y-5">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <h2 className="text-2xl font-bold text-slate-900">My Bookings</h2>
        <button type="button" onClick={fetchBookings} className="rounded-lg border border-slate-300 px-3 py-2 text-sm font-semibold text-slate-700 hover:bg-slate-100">
          Refresh
        </button>
      </div>

      <div className="grid gap-3 sm:grid-cols-3">
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Total Bookings</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{bookings.length}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Today</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">{todaysBookings}</p>
        </div>
        <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
          <p className="text-xs uppercase text-slate-500">Confirmed Revenue</p>
          <p className="mt-1 text-2xl font-bold text-slate-900">INR {totalRevenue}</p>
        </div>
      </div>

      <div className="rounded-xl bg-white p-4 shadow-travel ring-1 ring-slate-200">
        <input
          type="text"
          placeholder="Search by booking ID, bus, route, passenger"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="w-full rounded-lg border border-slate-300 px-3 py-2 text-sm outline-none focus:border-blue-500"
        />
      </div>

      {loading ? <p className="text-slate-600">Loading bookings...</p> : null}
      {!loading && error ? <div className="rounded-xl bg-red-50 p-6 text-center text-red-700 shadow-travel ring-1 ring-red-200">{error}</div> : null}
      {!loading && !error && filteredBookings.length === 0 ? (
        <div className="rounded-xl bg-white p-6 text-center text-slate-600 shadow-travel ring-1 ring-slate-200">No bookings found.</div>
      ) : null}

      <div className="grid gap-4">
        {filteredBookings.map((booking) => (
          <article key={booking._id} className="rounded-2xl bg-white p-5 shadow-travel ring-1 ring-slate-200">
            <div className="flex flex-wrap items-start justify-between gap-3">
              <div>
                <h3 className="text-lg font-bold text-slate-900">{booking.busName}</h3>
                <p className="text-sm text-slate-600">{booking.route}</p>
                <p className="mt-1 text-xs text-slate-500">Booking ID: {booking.bookingCode}</p>
              </div>
              <div className="flex flex-wrap items-center gap-2">
                <span className={`rounded-full px-3 py-1 text-xs font-semibold ${booking.status === "Cancelled" ? "bg-slate-100 text-slate-600" : "bg-emerald-100 text-emerald-700"}`}>
                  {booking.status}
                </span>
                <span className="rounded-full bg-blue-50 px-3 py-1 text-xs font-semibold text-blue-700">{booking.paymentMethod}</span>
              </div>
            </div>

            <div className="mt-4 grid gap-2 text-sm text-slate-700 md:grid-cols-2">
              <p><span className="font-medium">Boarding:</span> {booking.boardingPoint}</p>
              <p><span className="font-medium">Dropping:</span> {booking.droppingPoint}</p>
              <p><span className="font-medium">Travel Date:</span> {booking.travelDate}</p>
              <p><span className="font-medium">Seats:</span> {booking.selectedSeats.join(", ")}</p>
              <p><span className="font-medium">Passengers:</span> {booking.passengerDetails.map((p) => p.name).join(", ")}</p>
              <p><span className="font-medium">Total:</span> INR {booking.totalPrice}</p>
              <p><span className="font-medium">Booked At:</span> {new Date(booking.bookedAt).toLocaleString()}</p>
            </div>

            <div className="mt-4 flex flex-wrap justify-end gap-3">
              <button
                type="button"
                onClick={() => cancelBooking(booking._id)}
                disabled={booking.status === "Cancelled" || activeId === booking._id}
                className="rounded-lg border border-red-300 px-4 py-2 text-sm font-semibold text-red-600 transition hover:bg-red-50 disabled:cursor-not-allowed disabled:border-slate-200 disabled:text-slate-400"
              >
                {activeId === booking._id ? "Cancelling..." : "Cancel Booking"}
              </button>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
};

export default Bookings;
